import Foundation

let questions11: [QuizQuestion] = [
QuizQuestion(id:831,question:"O que é o 'sacerdócio de Aarão' e por que foi insuficiente segundo Hebreus?",options:["Era perfeito e suficiente","Era desnecessário desde o início","É ainda necessário hoje","O sacerdócio levítico/aarônico era"],correctIndex:3,explanation:"Hebreus 7:23-28; 10:1-4: a fraqueza do sacerdócio levítico — mortalidade dos sacerdotes, repetição dos sacrifícios, impossibilidade de aperfeiçoamento. Cristo como Sumo Sacerdote eterno superou tudo.",reference:"Hebreus 7:23-28; 10:1-4",category:.geral,propheticMeaning:"'Impossível que o sangue de touros e bodes remova pecados' (Hb 10:4) — o AT era sombra, não substância. O sangue animal cobria temporariamente; o sangue de Cristo remove definitivamente. A repetição dos sacrifícios era admissão de insuficiência."),
QuizQuestion(id:832,question:"O que é a 'consciência limpa' no NT (Hebreus 9:14; 1 Pedro 3:21)?",options:["A consciência purificada pelo sangue","Perfeição moral","Ausência de pecado futuros","Uma conquista espiritual tardia"],correctIndex:0,explanation:"Hebreus 9:14: a obra do sangue de Cristo vai além do externo (como a lei levítica) para o interior — purificando a consciência de 'obras mortas' para servir ao Deus vivo.",reference:"Hebreus 9:14; 1 Pedro 3:21",category:.geral,propheticMeaning:"A consciência purificada pelo sangue (Hb 9:14) é o cumprimento do Dia da Expiação — o sumo sacerdote entrava para purificar o povo externamente; Cristo entra na consciência para purificar internamente. A expiação definitiva atinge o âmago do ser."),
QuizQuestion(id:833,question:"O que é o 'pecado de Adão' e sua consequência universal segundo Romanos 5?",options:["Apenas o pecado pessoal de Adão sem","'Por um só homem o pecado entrou no","Um mito sem base histórica","Apenas uma metáfora para os pecados"],correctIndex:1,explanation:"Romanos 5:12-19: a queda de Adão trouxe condenação universal; a obediência de Cristo traz justificação universal aos que creem — o paralelo estrutural da soteriologia paulina.",reference:"Romanos 5:12",category:.geral,propheticMeaning:"O paralelo Adão-Cristo não é apenas pedagógico — é cosmológico. Uma humanidade sob Adão (caída, mortal, condenada); uma humanidade nova sob Cristo (justificada, vivificada, glorificada). Dois âncoras da história humana."),
QuizQuestion(id:834,question:"O que ensina o Salmo 19 sobre a revelação divina?",options:["Só a Escritura revela Deus","A natureza contradiz a Escritura","Duas revelações complementares: a","A revelação é apenas interior"],correctIndex:2,explanation:"Salmo 19: a revelação divina bifrontal — a criação revela a glória e o poder de Deus (suficiente para responsabilizar); a Palavra revela o caráter e o caminho da salvação (suficiente para salvar).",reference:"Salmos 19:1,7",category:.geral,propheticMeaning:"A conclusão do Salmo 19 (v.14): 'sejam as palavras da minha boca e a meditação do meu coração agradáveis diante de ti' — o duplo estímulo da criação e da Palavra culmina em adoração. Revelação que não leva à adoração foi mal compreendida."),
QuizQuestion(id:835,question:"O que Paulo diz sobre a 'graça de Deus que me basta' em 2 Coríntios 12:9?",options:["Sempre peça mais graça","A graça nunca é suficiente","Precisamos gerar mais graça","'A minha graça te é suficiente"],correctIndex:3,explanation:"2 Co 12:9: a suficiência da graça é o ponto central — não a remoção do sofrimento mas a presença de Deus no sofrimento. 'Quando sou fraco, então é que sou forte' (v.10).",reference:"2 Coríntios 12:9",category:.geral,propheticMeaning:"A 'suficiência' da graça (arkei — raiz de 'arco', o suficiente para não necessitar mais) transforma a falta em plenitude: não mais circunstâncias, mas Cristo como a suficiência. A fraqueza torna-se o lugar da glória divina."),
QuizQuestion(id:836,question:"O que Paulo chama de 'escândalo da cruz' em 1 Coríntios 1:23?",options:["'Pregamos a Cristo crucificado","Um problema de relações públicas","Uma vergonha temporária","Apenas o sofrimento de Jesus"],correctIndex:0,explanation:"1 Co 1:23: 'skandalon' (armadilha, tropeço) para judeus que esperavam Messias conqusitador; 'moría' (loucura) para gregos que buscavam sabedoria filosófica. O crucificado inverte ambas as expectativas.",reference:"1 Coríntios 1:23",category:.geral,propheticMeaning:"O escândalo da cruz é eterno — não apenas no século I. O ego humano recusa um Salvador que morreu como criminoso. A pregação da cruz 'é sempre um tropeço para o orgulho humano e loucura para a sabedoria autossuficiente.'"),
QuizQuestion(id:837,question:"O que significa 'Deus é amor' em 1 João 4:8?",options:["Que Deus sente emoções como os humanos","'Deus é amor' (ho Theos agapē estin)","Que Deus aprova tudo","Que Deus nunca julga"],correctIndex:1,explanation:"1 João 4:8,16: 'Deus é amor' é afirmação ontológica sobre a natureza divina. A evidência máxima: 'Deus nos amou e enviou seu Filho como propiciação' (v.10) — o amor que se sacrifica.",reference:"1 João 4:8-10",category:.geral,propheticMeaning:"'Deus é amor' e 'Deus é luz' (1 Jo 1:5) revelam que amor e santidade são igualmente constitutivos de Deus — não em tensão. A cruz os reconcilia: Deus amou o suficiente para satisfazer a própria santidade pela propiciação."),
QuizQuestion(id:838,question:"O que é o 'batismo do Espírito Santo' segundo Atos 1:5 e 1 Coríntios 12:13?",options:["Uma experiência posterior à conversão","Um dom apenas para apóstolos","A obra do Espírito Santo que une todos os...","Uma segunda bênção após o batismo na água"],correctIndex:2,explanation:"1 Coríntios 12:13: o batismo do Espírito é universal para todos os crentes — todos foram batizados num Espírito para formar um corpo. É distinto do batismo na água mas igualmente essencial.",reference:"1 Coríntios 12:13; Atos 1:5",category:.geral,propheticMeaning:"O batismo do Espírito incorporando crentes ao corpo de Cristo (1 Co 12:13) é a realidade de que o batismo na água é símbolo. O Espírito forma a unidade orgânica da Igreja que transcende denominações, culturas e séculos."),
QuizQuestion(id:839,question:"O que Paulo ensina sobre a 'gratidão' como 'vontade de Deus' em 1 Ts 5:18?",options:["A gratidão é opcional","Agradeça apenas pelas bênçãos materiais","Somente pastores têm essa obrigação","'Em tudo dai graças"],correctIndex:3,explanation:"1 Tessalonicenses 5:18: 'em tudo' (en panti) — em toda circunstância, a gratidão é a resposta cristã moldada pela confiança na soberania e bondade de Deus.",reference:"1 Tessalonicenses 5:18",category:.geral,propheticMeaning:"Gratidão 'em tudo' é possível apenas quando se crê que 'todas as coisas cooperam para o bem' (Rm 8:28) — a soberania de Deus sobre todas as circunstâncias é o fundamento teológico da gratidão incondicional."),
QuizQuestion(id:840,question:"O que é a 'renovação da mente' em Romanos 12:2?",options:["A transformação progressiva do","Estudo acadêmico da Bíblia","Um curso de treinamento","Apenas para teólogos"],correctIndex:0,explanation:"Romanos 12:2: 'metamorphousthe tē anakainosei tou noos' — a metamorfose (metamorfose!) da mente pela renovação contínua. É o processo de santificação aplicado à cognição.",reference:"Romanos 12:2",category:.geral,propheticMeaning:"A 'mente de Cristo' (1 Co 2:16) que o crente recebe pelo Espírito é desenvolvida pela renovação da mente — leitura da Palavra, meditação, oração e comunhão. O crente vai progressivamente pensando como Deus pensa sobre si mesmo, os outros e o mundo."),
QuizQuestion(id:841,question:"O que João ensina sobre 'andar na luz' em 1 João 1:7?",options:["Evitar toda exposição ao mal","'Se andarmos na luz, como ele está na luz","Viver sem pecados","Ser perfeito moralmente antes de ter"],correctIndex:1,explanation:"1 João 1:7: 'andar na luz' não é perfeição moral mas transparência e honestidade diante de Deus — o oposto de 'andar nas trevas' (v.6) que é esconder o pecado.",reference:"1 João 1:7",category:.geral,propheticMeaning:"'Andar na luz' que resulta em purificação contínua ('purifica' — katharizei, presente contínuo) mostra que a vida cristã não é chegada à perfeição mas jornada na transparência. O sangue de Cristo continua purificando enquanto andamos honestamente."),
QuizQuestion(id:842,question:"O que Paulo diz sobre a 'abundância de revelações' e o espinho em 2 Coríntios 12:7?",options:["Paulo nunca teve fraquezas","Paulo foi punido por Deus","'Para que não me exaltasse por","O espinho era falta de fé"],correctIndex:2,explanation:"2 Co 12:7: o 'espinho' (skolops — prego/farpão) dado para impedir a exaltação — Deus usando até a obra do adversário para proteção espiritual de Paulo.",reference:"2 Coríntios 12:7",category:.geral,propheticMeaning:"Deus usando 'o mensageiro de Satanás' para o bem de Paulo (guarda-lo humilde) ilustra a soberania divina sobre o mal — não que Deus aprovasse o sofrimento, mas que o governa para fins bons. 'Todas as coisas cooperam para o bem' inclui os ataques do adversário."),
QuizQuestion(id:843,question:"O que Hebreus 11:6 diz sobre a fé como condição de agradar a Deus?",options:["As obras agradam mais que a fé","A inteligência agrada a Deus","A fé é opcional para o cristão maduro","'Sem fé é impossível agradar a Deus"],correctIndex:3,explanation:"Hebreus 11:6: a fé como condição necessária e dupla — crer que Deus existe (sua realidade) e que recompensa os que o buscam (seu caráter bondoso). Ambos componentes são essenciais.",reference:"Hebreus 11:6",category:.geral,propheticMeaning:"'Galardoador dos que o buscam' — a fé não é apenas crença intelectual na existência de Deus, mas confiança em seu caráter benevolente. O agnosticismo moral ('Deus existe mas é indiferente') não é fé bíblica."),
QuizQuestion(id:844,question:"O que Tiago 5:16 ensina sobre a oração uns pelos outros?",options:["'Confessai os vossos pecados uns aos...","Ore apenas pelos seus pecados","Somente o pastor pode curar pelos outros","Confissão e oração são separadas"],correctIndex:0,explanation:"Tiago 5:16: confissão mútua e oração mútua em comunidade — a oração 'eficaz' (energoumenē — que opera ativamente) do justo tem grande poder.",reference:"Tiago 5:16",category:.geral,propheticMeaning:"A oração eficaz descrita em Tiago 5 tem contexto comunitário: anciãos, confissão mútua, prática de Elias (v.17-18). A oração não é ato privado isolado mas expressão da comunhão corporativa — a Igreja intercedendo uns pelos outros."),
QuizQuestion(id:845,question:"O que Paulo diz sobre a 'necessidade do evangelho' em 1 Coríntios 9:16?",options:["A pregação é opcional para Paulo","'Pois, se eu evangelizo","Somente apóstolos devem evangelizar","Paulo pregava por recompensa"],correctIndex:1,explanation:"1 Co 9:16: Paulo sente o evangelho como compulsão (anankē — necessidade, urgência) não como opção. 'Ai de mim' (ouai — lamento profético) expressa o peso da responsabilidade.",reference:"1 Coríntios 9:16",category:.geral,propheticMeaning:"A compulsão de evangelizar não vem de obrigação legal mas do amor de Cristo que constrange (2 Co 5:14) e do peso pela perdição dos homens. Paulo 'devedor tanto a gregos como a bárbaros' (Rm 1:14) — dívida de graça, não de mérito."),
QuizQuestion(id:846,question:"O que Jesus ensinou sobre obedecer os governantes religiosos em Mateus 23:3?",options:["Siga sempre os líderes religiosos","Desobedeça sempre os líderes religiosos","'Fazei e guardai tudo o que vos disserem","A prática é mais importante que o ensino"],correctIndex:2,explanation:"Mateus 23:1-3: Jesus ordenou guardar o que os fariseus ensinavam (a lei de Moisés) mas não imitar sua hipocrisia — separando a autoridade do cargo da credibilidade moral.",reference:"Mateus 23:1-3",category:.geral,propheticMeaning:"A distinção entre o que a liderança ensina (autoridade baseada na Palavra) e como vive (exemplificação pessoal) permanece relevante. A mensagem pode ser verdadeira mesmo quando o mensageiro é inconsistente — mas a hipocrisia sempre prejudica a proclamação."),
QuizQuestion(id:847,question:"O que Jesus disse sobre a 'carga leve' em Mateus 11:28-30?",options:["Que a vida cristã não tem desafios","Que o cristão nunca trabalhará","Que os sofrimentos desaparecem","'Vinde a mim"],correctIndex:3,explanation:"Mateus 11:28-30: o convite de Jesus é para os oprimidos pelo jugo da lei farisaica e pelo peso do pecado. O 'jugo suave' não é ausência de jugo mas jugo diferente — o de comunhão com Cristo.",reference:"Mateus 11:28-30",category:.geral,propheticMeaning:"'Tomai meu jugo sobre vós E APRENDEI de mim' — o descanso de Jesus não é passividade mas aprendizagem de seu modo de vida: 'sou manso e humilde de coração.' O descanso que ele oferece vem da transformação interior pelo seu caráter."),
QuizQuestion(id:848,question:"O que Paulo diz sobre a 'satisfação em todas as circunstâncias' em Filipenses 4:11?",options:["'Aprendi a contentar-me no","Paulo era sempre próspero","A pobreza é sempre melhor","A riqueza é sempre melhor"],correctIndex:0,explanation:"Filipenses 4:11-12: 'contentamento' (autarkeia — auto-suficiência, satisfação interior) é aprendido (emathhon — aprendi) — não dom automático, mas aprendizagem no processo das circunstâncias.",reference:"Filipenses 4:11-12",category:.geral,propheticMeaning:"Paulo aprendendo o contentamento nas 'escolas' da necessidade e da abundância mostra que a satisfação cristã não vem das circunstâncias mas da perspectiva de Cristo — 'posso tudo naquele que me fortalece' (Fp 4:13)."),
QuizQuestion(id:849,question:"O que é a 'oração de exame' na tradição cristã baseada no Salmo 139?",options:["Um ritual eclesiástico","A prática de revisar a presença de Deus","Uma forma de auto-condenação","Apenas para religiosos contemplativo"],correctIndex:1,explanation:"Salmo 139:23-24: 'sonda-me, ó Deus... vê se há em mim algum caminho mau' — a oração que convida Deus a revelar o que precisamos ver sobre nós mesmos.",reference:"Salmos 139:23-24",category:.geral,propheticMeaning:"'Vê se há em mim algum caminho perverso' (derech otsev — caminho de dor/ídolo) — não auto-condenação mas abertura à correção divina. O exame de consciência não é neuroses mas saúde espiritual: trazer a vida à presença de Deus para ser avaliada por ele."),
QuizQuestion(id:850,question:"O que Paulo ensina sobre 'fazer tudo para a glória de Deus' em 1 Coríntios 10:31?",options:["Somente atos religiosos glorificam a Deus","Apenas o ministério glorifica a Deus","'Se comeis, se bebeis ou fazeis qualquer","A glória de Deus é tema apenas para..."],correctIndex:2,explanation:"1 Co 10:31: a santificação do ordinário — comer e beber como exemplos do mais banal levados à dignidade de glória divina quando orientados pelo coração consagrado.",reference:"1 Coríntios 10:31",category:.geral,propheticMeaning:"'Qualquer coisa' inclui trabalho, família, descanso, alimentação — não há ato secular para o crente consagrado. A distinção sagrado/secular colapsa quando tudo é feito 'como para o Senhor' (Cl 3:23)."),
QuizQuestion(id:851,question:"O que é a 'imagem de Deus' (imago Dei) e como foi afetada pela queda?",options:["Completamente destruída pela queda","Não é afetada pelo pecado","Apenas os crentes têm a imagem de Deus","A imagem de Deus no ser humano (Gn 1:27)"],correctIndex:3,explanation:"A imago Dei foi distorcida pela queda (perdendo a retidão original — Cl 3:10) mas não destruída (Gn 9:6 ainda a cita como base do valor da vida humana). Cristo é a 'imagem perfeita de Deus' (Cl 1:15) que a restaura nos crentes.",reference:"Gênesis 1:27; Colossenses 3:10",category:.genesis,propheticMeaning:"A restauração da imagem de Deus (2 Co 3:18 — 'transformados da mesma glória em glória') é o objetivo da salvação: não apenas perdão de pecados mas renovação da humanidade à sua dignidade original e mais — na imagem de Cristo."),
QuizQuestion(id:852,question:"O que Paulo ensina sobre a 'confissão com a boca' em Romanos 10:9-10?",options:["'Se com a tua boca confessares Jesus","A confissão é apenas interna","A confissão é desnecessária para a...","Apenas o batismo é necessário"],correctIndex:0,explanation:"Romanos 10:9-10: a salvação tem dimensão interna (crença — coração) e externa (confissão — boca). A confissão não adiciona mérito mas é a expressão natural e necessária da fé genuína.",reference:"Romanos 10:9-10",category:.geral,propheticMeaning:"A confissão de 'Kyrios Iēsous' ('Jesus é Senhor') era politicamente perigosa no Império Romano onde 'Kyrios Caesar' era a confissão obrigatória. A confissão cristã é declaração de lealdade alternativa: Jesus, não César, é Senhor de tudo."),
QuizQuestion(id:853,question:"O que Paulo diz sobre a 'morte para o pecado' em Romanos 6:11?",options:["Que o pecado desaparece instantaneamente","'Considerai-vos mortos para o pecado","Que os crentes não pecam mais","Que a morte ao pecado é uma conquista"],correctIndex:1,explanation:"Romanos 6:11: o 'considerai-vos mortos ao pecado' é um ato de fé intencional — aplicar o que já é verdade ('nosso velho homem foi crucificado com Cristo' — v.6) ao presente.",reference:"Romanos 6:11",category:.geral,propheticMeaning:"'Considerai-vos' (logizesthe) é o mesmo verbo usado em Rm 4:3 para a imputação da fé de Abraão — um ato de reconhecimento da realidade. Assim como Abraão 'considerou' (crendo), o crente 'considera' sua morte ao pecado e age a partir dessa realidade."),
QuizQuestion(id:854,question:"O que Gênesis 1 revela sobre a criação e a bondade de Deus?",options:["A criação física é inerentemente má","A criação é apenas espiritual","Seis vezes 'e viu Deus que era bom' e no","O AT tem visão negativa da matéria"],correctIndex:2,explanation:"Gênesis 1: a repetição de 'era bom' (tov) afirma a bondade ontológica da criação material. O dualismo que vê a matéria como má é não-bíblico.",reference:"Gênesis 1:4,10,12,18,21,25,31",category:.genesis,propheticMeaning:"'Muito bom' (tov meod) aplicado à criação material fundamenta a encarnação (Deus entrando na matéria 'boa'), a ressurreição do corpo ('bom' para ser eterno) e a nova criação ('restauração do muito bom original')."),
QuizQuestion(id:855,question:"O que é o 'deserto' como lugar espiritual nos Evangelhos e no AT?",options:["Apenas geografia","Um lugar de abandono de Deus","Um símbolo sem significado espiritual","Um lugar de encontro com Deus"],correctIndex:3,explanation:"O deserto (midbar) como lugar de formação espiritual é tema recorrente: Is 40:3 (voz no deserto); Oséias 2:14 (levarei ao deserto para falar ao coração). O esvaziamento do deserto prepara para a plenitude.",reference:"Mateus 4:1; Oséias 2:14",category:.geral,propheticMeaning:"'Levarei ao deserto e falarei ao seu coração' (Os 2:14) — Deus usa o esvaziamento e a ausência de distrações para falar mais intimamente. O 'deserto' da vida (perdas, doenças, isolamento) pode ser o lugar do encontro mais profundo."),
QuizQuestion(id:856,question:"O que Paulo diz sobre a 'reconciliação de todas as coisas' em Colossenses 1:20?",options:["'Por meio dele","Apenas seres humanos são reconciliados","A reconciliação é apenas espiritual","O cosmos continua separado de Deus"],correctIndex:0,explanation:"Colossenses 1:20: a reconciliação cósmica pelo sangue de Cristo — não apenas pessoas mas 'todas as coisas,' incluindo a criação que geme (Rm 8:22).",reference:"Colossenses 1:20; Romanos 8:21",category:.geral,propheticMeaning:"A reconciliação cósmica de Cl 1:20 antecipa Apocalipse 21:5 ('faço novas todas as coisas') — a obra de Cristo não se limita ao coração humano mas envolve a restauração de toda a criação ao seu estado de 'muito bom' original."),
QuizQuestion(id:857,question:"O que é o 'louvor como sacrifício' em Hebreus 13:15?",options:["Uma oferta monetária","'Ofereçamos continuamente a Deus","Uma penitência religiosa","Uma prática apenas para cantores"],correctIndex:1,explanation:"Hebreus 13:15: o 'sacrifício de louvor' (zebach todah no AT; thysia aineseos no NT) — a vida cristã de adoração substituindo o sistema sacrificial levítico, cumprido em Cristo.",reference:"Hebreus 13:15",category:.geral,propheticMeaning:"'Fruto de lábios' como sacrifício transforma a fala cotidiana em adoração potencial — não apenas nos cultos mas em toda confissão do nome de Cristo no dia a dia. A vida cristã inteira é liturgia."),
QuizQuestion(id:858,question:"O que é a 'unção' em Tiago 5:14 e sua aplicação?",options:["Uma cerimônia sem efeito prático","Um exorcismo","Os presbíteros ungindo com óleo os...","Apenas uma tradição católica"],correctIndex:2,explanation:"Tiago 5:14: o óleo tinha uso medicinal e simbólico no AT — a unção dos presbíteros combina cuidado pastoral, intercessão coletiva e dependência soberana de Deus para a cura.",reference:"Tiago 5:14",category:.geral,propheticMeaning:"A unção no contexto de Tiago 5 está rodeada de confissão de pecados (v.16) e exemplos de oração eficaz (Elias — v.17). A cura não é automática pela unção mas produto da 'oração de fé' (v.15) em submissão à vontade de Deus."),
QuizQuestion(id:859,question:"O que é a 'santificação' do matrimônio segundo 1 Coríntios 7:14?",options:["Que cônjuge não-crente é automaticamente","Que casamentos mistos são proibidos","Que a santificação do cônjuge é garantida","'O marido incrédulo é santificado pela..."],correctIndex:3,explanation:"1 Co 7:14: Paulo ensina que o cônjuge crente santifica (separa para a esfera de Deus) o lar — não salva automaticamente, mas cria um ambiente especial de influência redentora.",reference:"1 Coríntios 7:14",category:.geral,propheticMeaning:"A influência santificadora do crente no lar exemplifica o princípio do 'sal' (Mt 5:13) — um elemento que penetra e preserva. A presença de um crente no lar cria um ambiente diferente de graça e oração."),
QuizQuestion(id:860,question:"O que Paulo ensina sobre a 'plenitude do tempo' da encarnação em Gálatas 4:4?",options:["'Mas, vindo a plenitude do tempo","A encarnação foi prematura","A encarnação foi acidente histórico","Deus agiu antes do tempo ideal"],correctIndex:0,explanation:"Gálatas 4:4: 'plenitude do tempo' (plērōma tou chronou) — Deus agindo no momento perfeito de sua soberania, quando as condições históricas estavam maduras: língua grega universal, paz romana, lei judaica preparando.",reference:"Gálatas 4:4",category:.geral,propheticMeaning:"A 'plenitude do tempo' revela providência histórica: o período helenístico criou língua universal (grego), Roma criou infraestrutura (estradas, paz), e o judaísmo criou o monoteísmo ético e as Escrituras — todas convergindo para o momento da encarnação."),
QuizQuestion(id:861,question:"O que Jesus disse sobre ser 'sal da terra' em Mateus 5:13?",options:["Uma metáfora decorativa","'Vós sois o sal da terra","Uma promessa de bênção material","Uma instrução sobre culinária"],correctIndex:1,explanation:"Mateus 5:13: o sal como agente de preservação (contra a corrupção), tempero (tornando a vida com sabor) e purificação. O perigo é perder a 'salinidade' — a distintividade cristã que torna a influência possível.",reference:"Mateus 5:13",category:.geral,propheticMeaning:"Sal 'insípido' (moranthe — sem sabor, desnecessário) é imagem do crente que perdeu sua distintividade pelo assimilação ao mundo — ainda presente, mas sem influência. A distintividade cristã não é separatismo mas diferença que beneficia o ambiente."),
QuizQuestion(id:862,question:"O que Jesus disse sobre ser 'luz do mundo' em Mateus 5:14-16?",options:["Esconda sua fé","A luz é apenas interna","'Vós sois a luz do mundo. Não se pode","Apenas pastores são luz do mundo"],correctIndex:2,explanation:"Mateus 5:14-16: a luz cristã não é isolada mas visível — e o objetivo não é glorificar o crente mas o Pai. Boas obras são o veículo; a glória de Deus é o destino.",reference:"Mateus 5:14-16",category:.geral,propheticMeaning:"A luz da cidade sobre o monte é visível à noite — a presença cristã no mundo deve ser notável sem ser ostentosa. As 'boas obras' que levam à glorificação do Pai são a ponte entre a vida santa do crente e o impacto missionário na comunidade."),
QuizQuestion(id:863,question:"O que Paulo ensina sobre a 'perseverança dos santos' em Filipenses 1:6?",options:["A salvação pode ser perdida","A perseverança depende apenas do crente","Alguns crentes serão abandonados por Deus","'Estou certo de que aquele que em vós"],correctIndex:3,explanation:"Filipenses 1:6: a certeza da perseverança fundada na fidelidade de Deus, não na constância humana. Deus que começou a obra é o mesmo que a completará.",reference:"Filipenses 1:6",category:.geral,propheticMeaning:"'Até ao dia de Cristo Jesus' — a perseverança dos santos está ancorada na escatologia. A mesma mão que iniciou a obra (regeneração) a conduzirá à conclusão (glorificação). A segurança não é presunção mas confiança no caráter do Executor."),
QuizQuestion(id:864,question:"O que é a 'fidelidade de Cristo' (pistis Christou) em Gálatas 2:16?",options:["Debate tradução: 'fé em Cristo' (fé","Nossa fidelidade a Cristo","Apenas a obediência de Cristo","A fé histórica sobre Cristo"],correctIndex:0,explanation:"Gálatas 2:16: 'pistis Christou' pode ser 'fé em Cristo' (genitivo objetivo) ou 'fidelidade de Cristo' (genitivo subjetivo). A salvação é tanto pela fidelidade de Cristo (objetiva) quanto pela fé nele (subjetiva).",reference:"Gálatas 2:16",category:.geral,propheticMeaning:"A 'fidelidade de Cristo' como fundamento objetivo complementa a 'fé em Cristo' como resposta subjetiva — nossa fé responde à sua fidelidade. Cristo foi fiel ao Pai e a nós onde Adão (e nós) fomos infiéis."),
QuizQuestion(id:865,question:"O que é a 'teologia da aliança' como estrutura bíblica?",options:["Uma invenção medieval","A leitura da Bíblia como história de...","Apenas uma interpretação calvinista","Uma doutrina apenas do AT"],correctIndex:1,explanation:"A teologia da aliança vê coerência e progressão nas alianças bíblicas — todas convergindo para Cristo, o 'Mediador de uma aliança melhor' (Hb 8:6), que une AT e NT numa narrativa contínua.",reference:"Hebreus 8:6; Gálatas 3:17",category:.geral,propheticMeaning:"As alianças são como anéis concêntricos expandindo o círculo dos beneficiários da graça: Adão (toda humanidade), Noé (toda criação), Abraão (todas as nações), Davi (o Rei eterno), Nova Aliança (toda pessoa que crê) — a graça se expandindo até abarcar tudo."),
QuizQuestion(id:866,question:"O que é a 'graça comum' segundo Mateus 5:45?",options:["A graça que salva todos...","Uma graça menor que a especial","'O Pai celestial faz nascer o sol","Um conceito não bíblico"],correctIndex:2,explanation:"Mateus 5:45: a 'graça comum' (gratia communis) — as bênçãos providenciais de Deus para toda a humanidade: saúde, beleza, inteligência, chuva, colheitas. Distintas da graça salvadora (gratia specialis).",reference:"Mateus 5:45; Atos 14:17",category:.geral,propheticMeaning:"A graça comum serve múltiplos propósitos: demonstra a bondade de Deus, responsabiliza o não-crente que recebe sem reconhecer a fonte (Rm 1:21), e cria o tecido de civilização que torna a missão possível."),
QuizQuestion(id:867,question:"O que Paulo ensina sobre a 'exortação mútua' em Hebreus 3:13?",options:["A formação espiritual é solitária","A exortação é papel apenas do pastor","A exortação é repreensão pública","'Exortai-vos uns aos outros cada dia"],correctIndex:3,explanation:"Hebreus 3:13: a exortação diária como proteção contra o endurecimento — a comunidade cristã como ambiente onde cada membro fortalece e adverte os outros.",reference:"Hebreus 3:13",category:.geral,propheticMeaning:"'Enquanto ainda se chama hoje' revela urgência escatológica — o 'hoje' da graça não dura para sempre, e o endurecimento é progressivo. A exortação mútua diária é proteção contra o deslize gradual que a solidão não detecta."),
QuizQuestion(id:868,question:"Qual é a grande inclusão estrutural do evangelho de Mateus?",options:["Mateus abre com 'Emanuel","Nascimento e morte","Criação e nova criação","Israel e a Igreja"],correctIndex:0,explanation:"Mateus 1:23 (Emanuel = 'Deus conosco') e 28:20 ('estou convosco todos os dias, até à consumação dos séculos') formam um envelope narrativo — a presença de Jesus permeia todo o evangelho.",reference:"Mateus 1:23; 28:20",category:.geral,propheticMeaning:"'Estou convosco todos os dias' é a promessa que sustenta toda a missão — não 'ide e contai comigo' mas 'ide e eu estou convosco.' A missão é possível não pela competência do missionário mas pela presença contínua de Cristo."),
QuizQuestion(id:869,question:"O que é a 'oração pelo perdão' no Pai Nosso e sua condição?",options:["O perdão de Deus é automático sem","'Perdoa-nos as nossas dívidas","O perdão de Deus não depende de nada","Esta é a oração menos importante do Pai"],correctIndex:1,explanation:"Mateus 6:12,14-15: a ligação entre receber e conceder perdão. Não é merecer o perdão divino pelo nosso perdão, mas a recepção genuína do perdão divino naturalmente flui em perdão aos outros.",reference:"Mateus 6:12-15",category:.geral,propheticMeaning:"A parábola do servo implacável (Mt 18:23-35) expande este princípio: receber perdão imensurável (10.000 talentos) e recusar perdoar o pequeno (100 denários) é absurdo e perigo espiritual real. O perdão recebido genuinamente transforma em perdão concedido."),
QuizQuestion(id:870,question:"O que Paulo diz sobre a 'vida oculta em Cristo' em Colossenses 3:3?",options:["O crente vive a vida cristã visivelmente","A vida cristã é apenas futura","'Porque morrestes","O crente deve esconder sua fé"],correctIndex:2,explanation:"Colossenses 3:3: a identidade cristã está 'oculta' (kekryptai — escondida, guardada com segurança) em Cristo em Deus — a fonte de vida invisível ao mundo mas real. Revelada plenamente na parusia.",reference:"Colossenses 3:3-4",category:.geral,propheticMeaning:"'Escondida com Cristo em Deus' é a mais segura proteção possível — a vida cristã está guardada no interior da Trindade. Nenhum poder externo pode roubá-la porque está além do alcance de tudo que existe no tempo e no espaço."),
QuizQuestion(id:871,question:"O que é o 'milagre da multiplicação dos pães' segundo João 6?",options:["Uma parábola sobre partilha","Uma metáfora sobre abundância","Um evento apenas simbólico","Jesus alimentou 5.000 homens com"],correctIndex:3,explanation:"João 6:1-15: o milagre da multiplicação revelou Jesus como o novo Moisés que provê maná. Mas o discurso seguinte (v.26-58) revelou que o verdadeiro pão é sua própria carne — o que ofendeu muitos.",reference:"João 6:1-15,35",category:.geral,propheticMeaning:"O 'pão da vida' (Jo 6:35) é a interpretação que Jesus deu ao próprio milagre — ele não apenas multiplica pão físico mas é o alimento que satisfaz a fome espiritual eterna. O maná prefigurava; ele é a realidade prefigurada."),
QuizQuestion(id:872,question:"O que Jesus ensinou sobre o sábado em Marcos 2:27?",options:["'O sábado foi feito por causa do homem","O sábado é mais importante que os humanos","O sábado deve ser abolido","O sábado é lei absoluta sem exceções"],correctIndex:0,explanation:"Marcos 2:27: Jesus corrigiu a distorção farisaica do sábado — que se tornara um fardo de 39 categorias de trabalho proibido — restaurando seu propósito original: beneficiar o ser humano.",reference:"Marcos 2:27-28",category:.geral,propheticMeaning:"'O Filho do Homem é Senhor também do sábado' (Mc 2:28) — Jesus como o verdadeiro descanso antecipado pelo sábado. Hebreus 4:9-10 aplica: o descanso sabático que o crente encontra em Cristo é o cumprimento do sábado."),
QuizQuestion(id:873,question:"O que Paulo diz sobre orar em toda oportunidade em Efésios 6:18?",options:["Ore apenas nos cultos","'Orando em todo o tempo com toda a","A oração é a armadura de Deus","Ore apenas em momentos de crise"],correctIndex:1,explanation:"Efésios 6:18: a oração encerra a lista da armadura de Deus — não como peça adicional mas como o ar que o guerreiro respira. Todo o conjunto de armas opera em contexto de oração.",reference:"Efésios 6:18",category:.geral,propheticMeaning:"A oração como complemento da armadura revela que a batalha espiritual não é apenas ativa (lutar) mas receptiva (orar — receber o que Deus quer dar). Sem oração, a armadura é usada por força própria; com oração, é investida de poder divino."),
QuizQuestion(id:874,question:"O que Jesus disse sobre o amor entre os discípulos como testemunho em João 13:35?",options:["A doutrina é o melhor testemunho","Os milagres são o melhor testemunho","'Nisto todos conhecerão que sois meus","A obediência às regras é o melhor"],correctIndex:2,explanation:"João 13:34-35: o 'mandamento novo' de amar como Cristo amou é tanto ético quanto missionário — o amor da comunidade cristã é o argumento mais poderoso para a realidade de Cristo.",reference:"João 13:34-35",category:.geral,propheticMeaning:"'Todos conhecerão' — o amor fraternal não é apenas virtude interna mas missão externa. A Igreja que genuinamente se ama é a prova empírica de que Cristo é real e o evangelho transforma. É o apologético que nenhum argumento pode refutar."),
QuizQuestion(id:875,question:"O que Paulo diz sobre a 'unidade na diversidade' em 1 Coríntios 12?",options:["Todos devem ter os mesmos dons","Os dons iguais garantem unidade","A diversidade é obstáculo para a unidade","O corpo de Cristo tem muitos membros com..."],correctIndex:3,explanation:"1 Coríntios 12: a analogia do corpo — muitas partes, um corpo — explica que diversidade de dons não é desordem mas design divino. A unidade se expressa na diversidade, não na uniformidade.",reference:"1 Coríntios 12:4-7,12",category:.geral,propheticMeaning:"O Espírito Santo distribuindo 'a cada um em particular como quer' (1 Co 12:11) garante que nenhum dom é supérfluo e nenhum membro é desnecessário. A Igreja que honra a diversidade de dons reflete a sabedoria plural de Deus (Ef 3:10)."),
QuizQuestion(id:876,question:"Qual é o significado do véu rasgado no templo em Mateus 27:51?",options:["'O véu do templo se rasgou em dois","O templo foi destruído naquele momento","Uma coincidência natural","Um sinal de juízo sobre o sacerdócio"],correctIndex:0,explanation:"Mateus 27:51: o véu rasgado 'de cima a baixo' (por Deus, não por mãos humanas) é a resposta divina à morte de Jesus — o sumo sacerdote entrava no Santo dos Santos uma vez por ano; agora todos têm acesso contínuo.",reference:"Mateus 27:51; Hebreus 10:19-20",category:.geral,propheticMeaning:"Hebreus 10:19-20: o 'novo e vivo caminho' através do véu 'que é a sua carne' — o corpo de Cristo rasgado na cruz é o véu rasgado que abre o caminho ao Pai. A morte de Cristo não fechou o acesso; o abriu definitivamente."),
QuizQuestion(id:877,question:"O que Paulo ensina sobre 'não ceder à inveja' em Gálatas 5:26?",options:["A inveja é natural","'Não sejamos presunçosos","A inveja motiva o crescimento","Inveja e ciúme são necessários"],correctIndex:1,explanation:"Gálatas 5:26: Paulo finaliza a lista dos frutos da carne (v.19-21) com a advertência prática — a presunção (kenodoxia — glória vã) que provoca inveja corroe a vida comunitária.",reference:"Gálatas 5:26",category:.geral,propheticMeaning:"'Glória vã' (kenodoxia — literalmente 'glória oca/vazia') é o auto-engano do que busca status e reconhecimento baseados em nada real. O antídoto é 'fazer nada por rivalidade ou por vanglória' mas 'em humildade estimar os outros superiores a si mesmo' (Fp 2:3)."),
QuizQuestion(id:878,question:"O que é o 'pão da proposição' no tabernáculo e seu significado tipológico?",options:["Um pão para os sacerdotes comerem","Um pão para os peregrinos","Os doze pães de trigo colocados na mesa","Um símbolo sem significado"],correctIndex:2,explanation:"Êxodo 25:23-30; Levítico 24:5-9: o pão da proposição (lehem hapanim — 'pão das faces/presença') permanecia continuamente na presença de Deus. Jesus chamou-se 'pão da vida' (João 6).",reference:"Êxodo 25:23-30; João 6:35",category:.geral,propheticMeaning:"O 'pão das faces' (presença) prefigura Cristo como o pão permanentemente presente diante do Pai em nosso favor — nossa intercessão e nosso sustento espiritual. Como o pão era renovado semanalmente, Cristo continua apresentando-se como nosso representante."),
QuizQuestion(id:879,question:"O que Paulo diz sobre a 'morte de Cristo pela Igreja' em Efésios 5:25?",options:["Cristo morreu por todos igualmente sem","Cristo amou a Israel apenas","A morte de Cristo foi apenas por crentes","'Maridos, amai vossas mulheres"],correctIndex:3,explanation:"Efésios 5:25: Paulo usa o amor de Cristo pela Igreja como padrão para o amor conjugal — a entrega sacrificial (heauton paredōken — entregou a si mesmo) é o modelo.",reference:"Efésios 5:25",category:.geral,propheticMeaning:"'Entregou-se por ela' (pela Igreja) revela que a morte de Cristo tem dimensão comunitária — não apenas por indivíduos somados mas pela Igreja como entidade que ele ama como esposa. O amor conjugal é miniatura da relação Cristo-Igreja."),
QuizQuestion(id:880,question:"O que é o 'dom do discernimento de espíritos' em 1 Coríntios 12:10?",options:["O dom sobrenatural de distinguir entre","Julgamento de pessoas","Um dom de psicologia espiritual","Reconhecer quem é cristão verdadeiro"],correctIndex:0,explanation:"1 Co 12:10; 1 Jo 4:1: o discernimento de espíritos é o dom que protege a Igreja de se enganar com o que parece espiritual mas tem outra origem. É sempre exercido em comunidade, não isoladamente.",reference:"1 Coríntios 12:10; 1 João 4:1",category:.geral,propheticMeaning:"O discernimento de espíritos é necessário porque Satanás se disfarça de 'anjo de luz' (2 Co 11:14) e seus servos de 'ministros de justiça' (v.15) — o sobrenatural aparente não é automaticamente do Espírito Santo. A Palavra e a comunidade são o crivo."),
QuizQuestion(id:881,question:"O que Paulo diz sobre a 'renúncia ao ministério' em 2 Timóteo 4:10 sobre Demas?",options:["Demas foi punido por Deus","'Demas me abandonou","Demas simplesmente viajou","Demas foi enviado em missão"],correctIndex:1,explanation:"2 Timóteo 4:10: Demas, mencionado positivamente em Colossenses 4:14 e Filemom 24, abandonou Paulo 'amando o presente século.' O amor ao mundo pode custar o ministério e a fidelidade.",reference:"2 Timóteo 4:10",category:.geral,propheticMeaning:"Demas serve como advertência: a apostasia não começa com decisão dramática mas com amor crescente por 'o presente século' — as distrações, riquezas e prazeres temporais que aos poucos deslocam o amor a Cristo. 'Não ameis o mundo' (1 Jo 2:15) é proteção preventiva."),
QuizQuestion(id:882,question:"O que Pedro ensina sobre o 'sacerdócio real' e a 'pedra viva' em 1 Pedro 2?",options:["Apenas o clero é sacerdote","Apenas o sacerdócio levítico importa","Cristo como a 'pedra viva' e os crentes","A Igreja não tem função sacerdotal"],correctIndex:2,explanation:"1 Pedro 2:4-9: o cumprimento de Êxodo 19:6 — o que Israel foi chamado a ser (nação sacerdotal), a Igreja é em Cristo. O sacerdócio é de todos os crentes, não apenas de uma classe.",reference:"1 Pedro 2:4-9; Êxodo 19:6",category:.geral,propheticMeaning:"'Para oferecer sacrifícios espirituais' (1 Pe 2:5) — o sacerdócio real não oferece sangue de animais mas louvor, boas obras, serviço e a própria vida (Rm 12:1). A vida cristã inteira é culto sacerdotal."),
QuizQuestion(id:883,question:"O que Apocalipse 19:11-16 revela sobre o Cristo da segunda vinda?",options:["Cristo virá pacificamente","Cristo virá apenas para os crentes","A segunda vinda é apenas espiritual","João viu o céu aberto e 'aquele que se"],correctIndex:3,explanation:"Apocalipse 19:11-16: a imagem do Cristo conquistador — diferente do humilde servo da encarnação, o retorno é como Rei guerreiro com poder e autoridade universal.",reference:"Apocalipse 19:11-16",category:.geral,propheticMeaning:"'Rei dos reis e Senhor dos senhores' (Ap 19:16) é o título que todo joelho deve confessar (Fp 2:10-11). O 'manso e humilde de coração' (Mt 11:29) retorna como o 'Leão de Judá' (Ap 5:5) — as duas imagens são do mesmo Cristo, reveladas em momentos diferentes."),
QuizQuestion(id:884,question:"O que Apocalipse 5:5-6 revela sobre o paradoxo do Cordeiro-Leão?",options:["João ouviu 'o Leão de Judá' mas viu 'um","São duas pessoas diferentes","A revelação é contraditória","O Cordeiro é mais importante que o Leão"],correctIndex:0,explanation:"Apocalipse 5:5-6: o paradoxo central da cristologia joanina — o conquistador é o sacrificado. O Leão vence como Cordeiro; o Cordeiro reina como Leão. A vitória vem pelo sacrifício.",reference:"Apocalipse 5:5-6",category:.geral,propheticMeaning:"'Venceu para abrir o livro' (Ap 5:5) — a vitória de Cristo que qualifica para abrir os selos da história foi conquistada pela morte (v.9: 'foste morto e compraste com o teu sangue'). O poder da história está nas mãos do Cordeiro imolado que vive."),
QuizQuestion(id:885,question:"O que é a 'adoração dos 24 anciãos' em Apocalipse 4-5?",options:["Uma liturgia humana","Os 24 anciãos lançando suas","Uma cena futurista apenas","Apenas anjos adorando"],correctIndex:1,explanation:"Apocalipse 4:9-11; 5:8-10: os 24 anciãos (provavelmente representando Israel e a Igreja — 12+12) adoram o Criador e o Redentor — a liturgia celestial que a adoração terrena reflete e antecipa.",reference:"Apocalipse 4:10-11; 5:9-10",category:.geral,propheticMeaning:"'Compraste para Deus, com o teu sangue, homens de toda tribo, língua, povo e nação' (Ap 5:9) — a adoração do Cordeiro é adoração pela obra da redenção universal. O motivo da adoração é sempre o que Deus fez, não apenas quem ele é."),
QuizQuestion(id:886,question:"O que Paulo diz sobre a 'loucura da pregação' em 1 Coríntios 1:21?",options:["A pregação deve ser intelectualmente","A pregação é secundária ao exemplo de vida","'Visto que na sabedoria de Deus o mundo","Os intelectuais nunca aceitam o evangelho"],correctIndex:2,explanation:"1 Co 1:21: 'moría tou kērygmatos' — a loucura da proclamação (kērygma) é o meio escolhido por Deus para salvar. Não filosofia, não espetáculo, mas proclamação da mensagem.",reference:"1 Coríntios 1:21",category:.geral,propheticMeaning:"Deus usando a 'loucura da pregação' revela seu método característico: o fraco que confunde o forte, o simples que supera o sábio, a oralidade que transforma onde a escrita falha. A pregação é a ferramenta divina primária porque depende do Espírito para o efeito."),
QuizQuestion(id:887,question:"O que é o 'crescimento em graça e no conhecimento' em 2 Pedro 3:18?",options:["Crescimento automático","Crescimento apenas intelectual","Crescimento é apenas para novos crentes","'Crescei na graça e no conhecimento do"],correctIndex:3,explanation:"2 Pedro 3:18: o imperativo de crescer — graça (relacionamento) e conhecimento (revelação) de Jesus Cristo são inseparáveis e progressivos. Pedro encerra sua segunda carta com a visão escatológica e este imperativo.",reference:"2 Pedro 3:18",category:.geral,propheticMeaning:"Crescer 'em graça' e 'no conhecimento' de Cristo como objetivo final — não crescer em dons, nem em posição, nem em influência, mas conhecer Cristo mais profundamente. Paulo dizia: 'Estimo todas as coisas como perda para ganhar Cristo' (Fp 3:8)."),
QuizQuestion(id:888,question:"O que Paulo diz sobre o 'cuidado mútuo' no corpo em 1 Coríntios 12:25-26?",options:["'Para que não haja divisão no corpo","Cada um cuide apenas de si","O cuidado é responsabilidade do pastor","Apenas os fracos precisam de cuidado"],correctIndex:0,explanation:"1 Co 12:25-26: a interdependência orgânica do corpo — o sofrimento e a alegria de um membro são coletivos. O corpo genuinamente une a alegria e a dor.",reference:"1 Coríntios 12:25-26",category:.geral,propheticMeaning:"'Se um membro sofre, todos sofrem' é a medida do nível de comunhão real — uma Igreja onde a dor de um membro não chega aos outros não é um corpo mas uma coleção de indivíduos. A koinonia genuína sente junto."),
QuizQuestion(id:889,question:"O que Paulo diz sobre a 'moderação' ou 'gentileza' em Filipenses 4:5?",options:["Seja assertivo sempre","'A vossa moderação (epieikeia","Seja severo com os outros","A gentileza é fraqueza"],correctIndex:1,explanation:"Filipenses 4:5: 'epieikeia' é a disposição de ceder dos próprios direitos por amor — a 'razoabilidade, gentileza, equanimidade.' 'O Senhor está próximo' motiva: se ele virá julgar, não preciso defender meus direitos agora.",reference:"Filipenses 4:5",category:.geral,propheticMeaning:"'O Senhor está próximo' como motivação para a gentileza revela a lógica escatológica da ética: porque o julgamento final de Deus vem, posso ceder meus direitos temporais agora. A escatologia liberta para a generosidade ética."),
QuizQuestion(id:890,question:"O que é a 'aceitação um do outro' em Romanos 15:7?",options:["Aceitar qualquer comportamento","Apenas aceitar os que concordam conosco","'Aceitai-vos uns aos outros","Aceitar apenas membros da mesma"],correctIndex:2,explanation:"Romanos 15:7: a aceitação mútua 'como Cristo nos aceitou' supera diferenças de prática (o 'forte' e o 'fraco' de Rm 14-15) — o padrão é a graça de Cristo, não a homogeneidade cultural.",reference:"Romanos 15:7",category:.geral,propheticMeaning:"'Como Cristo nos aceitou' é o padrão radical: ele nos aceitou enquanto ainda éramos pecadores (Rm 5:8). Se a aceitação de Cristo não esperou nossa perfeição, a aceitação mútua cristã também não pode condicioná-la à conformidade."),
QuizQuestion(id:891,question:"O que é a 'provisão divina no deserto' (Êxodo 16) e seu significado?",options:["Uma lenda israelita","Uma história de múltiplos milagres sem","Um evento apenas para Israel antigo","Deus proveu maná para Israel no deserto"],correctIndex:3,explanation:"Êxodo 16: o maná — dependência diária (não acumulação), provisão sobrenatural, descanso sabático. Jesus em João 6:32-33: 'o verdadeiro pão do céu é o que desce do céu e dá vida ao mundo.'",reference:"Êxodo 16:4; João 6:32-35",category:.profetas,propheticMeaning:"O maná que não podia ser acumulado sem apodrecer ensina que a graça de Deus não pode ser 'estocada' — é renovada diariamente. A dependência diária de Deus que o maná criou em Israel é o ritmo de vida que Jesus ensina no Pai Nosso: 'o pão nosso de cada dia.'"),
QuizQuestion(id:892,question:"O que foi a travessia do mar Vermelho e seu significado em 1 Coríntios 10?",options:["Israel passando pelo mar a pé enquanto","Apenas um evento histórico","Uma parábola sobre a libertação","Um evento sobrenatural sem tipologia"],correctIndex:0,explanation:"Êxodo 14; 1 Co 10:1-4: a travessia do mar como tipo do batismo, a nuvem como tipo do Espírito, e o maná/água da rocha como tipo de Cristo. Paulo usa o Êxodo como prefiguração da vida cristã.",reference:"Êxodo 14:21-31; 1 Coríntios 10:1-4",category:.profetas,propheticMeaning:"'A rocha espiritual... era Cristo' (1 Co 10:4) — Paulo identificando a rocha que fornecia água no deserto como Cristo preexistente. O Filho eterno já estava presente e ativo no Êxodo, sustentando Israel antes da encarnação."),
QuizQuestion(id:893,question:"Qual é o papel do Espírito Santo na inspiração da Escritura segundo 2 Pedro 1:21?",options:["Os autores inventaram o conteúdo","'A profecia não teve como origem à","A Bíblia é apenas livro humano","O Espírito ditou mecanicamente"],correctIndex:1,explanation:"2 Pedro 1:20-21: a origem divina da Escritura — não veio da vontade humana mas de homens 'movidos' (pheromenoi — levados como velas pelo vento) pelo Espírito Santo.",reference:"2 Pedro 1:21; 2 Timóteo 3:16",category:.geral,propheticMeaning:"'Movidos pelo Espírito' como velas pelo vento revela a dinâmica da inspiração: os autores eram agentes reais (suas personalidades, vocabulários e contextos aparecem) mas movidos pelo Espírito (origem e garantia divina). Inspiração plena e instrumental simultaneamente."),
QuizQuestion(id:894,question:"O que Paulo diz sobre a 'consolação dos sofrimentos' em 2 Coríntios 1:3-4?",options:["O sofrimento não tem propósito","A consolação é apenas futura","'O Pai das misericórdias e Deus de toda a...","Apenas líderes recebem consolação divina"],correctIndex:2,explanation:"2 Co 1:3-4: o fluxo da consolação — de Deus→ao crente sofredor→aos outros que sofrem. O sofrimento não é desperdiçado quando produz capacidade de consolar.",reference:"2 Coríntios 1:3-4",category:.geral,propheticMeaning:"Paulo que sofreu naufrágio, prisão, espancamentos e rejeição escreveu sobre consolação que vem de ter sido consolado. A autoridade para consolar vem da experiência do sofrimento consolado — o líder espiritual mais eficaz é frequentemente o mais testado."),
QuizQuestion(id:895,question:"O que Paulo ensina sobre a 'humildade de Cristo' como modelo em Filipenses 2:3-5?",options:["Cristo era assertivo e self-confident","Humildade é fraqueza","Apenas líderes devem ser humildes","'Nada façais por contenda ou por..."],correctIndex:3,explanation:"Fp 2:3-5: a 'mente de Cristo' (phronēma Christou) como modelo de relações na comunidade — a humildade não como sentimento mas como postura de 'estimar os outros superiores.'",reference:"Filipenses 2:3-5",category:.geral,propheticMeaning:"'Tende o mesmo sentimento que houve em Cristo Jesus' — a kenose de Cristo (v.6-8) é o fundamento da humildade chamada (v.3-5). A humildade cristã não é autodesprezo mas imagem de Cristo que, sendo o maior, tomou a posição do menor."),
QuizQuestion(id:896,question:"O que ensina o Salmo 46 sobre a presença de Deus como refúgio?",options:["'Deus é o nosso refúgio e fortaleza","Deus está distante nas crises","Deus ajuda apenas quando procurado","Refúgio em Deus é apenas sentimento"],correctIndex:0,explanation:"Salmo 46:1-2: o Deus presente nas tribulações ('muito presente' — nimtsa meod) torna o crente inabalável mesmo quando 'a terra se muda e os montes se movem.' Lutero baseou 'Castelo Forte' neste salmo.",reference:"Salmos 46:1-2",category:.geral,propheticMeaning:"'Estar quieto e saber que eu sou Deus' (Sl 46:10) — no caos da batalha e dos terremotos, o conhecimento da soberania de Deus produz quietude interior. Não ignorância da realidade mas confiança no Senhor das realidades."),
QuizQuestion(id:897,question:"O que é a 'oração intercessória' de Paulo em Efésios 1:17-19?",options:["Uma lista de pedidos materiais","Paulo ora para que os efésios recebam:","Uma bênção formal","Uma oração apenas pelo crescimento"],correctIndex:1,explanation:"Efésios 1:17-19: a oração intercessória de Paulo por revelação, iluminação e poder — o que os crentes precisam não é mais habilidade ou recurso, mas mais conhecimento de Deus.",reference:"Efésios 1:17-19",category:.geral,propheticMeaning:"'O espírito de sabedoria e revelação no conhecimento de Cristo' como pedido central de Paulo revela o que ele valorizava mais: não o crescimento da Igreja, não a saúde dos membros, mas o conhecimento mais profundo de quem Cristo é."),
QuizQuestion(id:898,question:"O que é o conceito de 'plenitude de Cristo' em Efésios 1:23?",options:["A Igreja é superior a Cristo","A Igreja complementa o que falta em Cristo","'A Igreja, que é o seu corpo","Cristo é incompleto sem a Igreja"],correctIndex:2,explanation:"Efésios 1:23: a Igreja como 'corpo' de Cristo é o meio pelo qual ele continua sua presença no mundo — não que Cristo seja incompleto, mas que a Igreja é o lugar onde sua plenitude é expressa e experienciada.",reference:"Efésios 1:22-23",category:.geral,propheticMeaning:"A Igreja como corpo de Cristo no mundo significa que quando a Igreja ama, serve, proclama e cura, Cristo está fazendo isso através de seu corpo. É a encarnação continuada — não em sentido ontológico mas missional e sacramental."),
QuizQuestion(id:899,question:"O que Paulo diz sobre o 'noivado espiritual' em 2 Coríntios 11:2?",options:["Uma metáfora sobre liderança","Uma metáfora sobre o AT","Uma comparação com o casamento de Adão e...","'Tenho-vos prometido a um único esposo"],correctIndex:3,explanation:"2 Co 11:2: a Igreja como noiva prometida a Cristo, com Paulo no papel de pai/padrinho. A 'serpente enganando Eva' (v.3) como tipo das falsas doutrinas que corrompem a fidelidade virginal.",reference:"2 Coríntios 11:2-3",category:.geral,propheticMeaning:"O 'noivado' entre Cristo e a Igreja estabelece lealdade exclusiva — infidelidade doutrinária é adulterio espiritual. Paulo usando linguagem de noivado (como os profetas em relação a Israel) revela o peso de ser fiel ao Cristo bíblico contra os 'evangelhos' alternativos."),
QuizQuestion(id:900,question:"Qual é a grande doxologia paulina em Efésios 3:20-21?",options:["'Àquele que é poderoso para fazer","Uma fórmula litúrgica vazia","Uma oração de encerramento","Uma bênção apenas para líderes"],correctIndex:0,explanation:"Efésios 3:20-21: Paulo encerra a seção doutrinária da carta com doxologia — o Deus capaz de 'huperekperissou' (imensamente mais, supraabundantemente além) de tudo que pensamos ou pedimos.",reference:"Efésios 3:20-21",category:.geral,propheticMeaning:"'Infinitamente mais do que tudo quanto pedimos ou pensamos' (huperekperissou) — a capacidade de Deus excede tanto a oração quanto a imaginação. A teologia paulina não termina em sistema mas em adoração: o conhecimento de Deus transborda em doxologia."),
]
